const refreshProductVariantCaches = `-- name: RefreshProductVariantCaches :exec
UPDATE products p
SET
  min_price = (
    SELECT COALESCE(MIN(pv.effective_price), 0) FROM product_variants pv
    WHERE pv.product_id = p.id AND pv.deleted_at IS NULL
  ),
  max_price = (
    SELECT COALESCE(MAX(pv.effective_price), 0) FROM product_variants pv
    WHERE pv.product_id = p.id AND pv.deleted_at IS NULL
  ),
  total_stock = (
    SELECT COALESCE(SUM(pv.stock), 0) FROM product_variants pv
    WHERE pv.product_id = p.id AND pv.deleted_at IS NULL
  ),
  updated_at = NOW()
WHERE p.id = ?
`

func (q *Queries) RefreshProductVariantCaches(ctx context.Context, id types.BinaryUUID) error {
	_, err := q.db.ExecContext(ctx, refreshProductVariantCaches, id)
	return err
}

