const searchProducts = `-- name: SearchProducts :many
SELECT p.id, p.vendor_id, p.category_id, p.name, p.description, p.brand, p.gender, p.sku, p.min_price, p.max_price, p.total_stock, p.rating, p.review_count, p.status, p.bestseller, p.new_arrival, p.featured, p.trending, p.created_at, p.updated_at FROM products p
LEFT JOIN categories c ON c.id = p.category_id
WHERE p.status = 'active'
  AND p.total_stock > 0
  AND (? IS NULL OR p.name LIKE CONCAT('%', ?, '%') OR p.description LIKE CONCAT('%', ?, '%') OR p.brand LIKE CONCAT('%', ?, '%'))
  AND (? IS NULL OR c.slug = ? OR c.name = ?)
  AND (? IS NULL OR EXISTS (
    SELECT 1 FROM categories child
    WHERE child.id = p.category_id AND child.slug = ?
  ))
  AND (? IS NULL OR p.brand = ?)
  AND (? IS NULL OR p.gender = ?)
  AND (? IS NULL OR p.vendor_id = ?)
  AND (? IS NULL OR EXISTS (
    SELECT 1 FROM product_variants pv
    WHERE pv.product_id = p.id AND pv.size = ? AND pv.deleted_at IS NULL AND pv.stock > 0
  ))
  AND (? IS NULL OR EXISTS (
    SELECT 1 FROM product_variants pv
    WHERE pv.product_id = p.id AND pv.color = ? AND pv.deleted_at IS NULL AND pv.stock > 0
  ))
  AND (? IS NULL OR p.min_price >= ?)
  AND (? IS NULL OR p.max_price <= ?)
  AND (? IS NULL OR p.rating >= ?)
  AND (? = false OR p.featured = true)
  AND (? = false OR p.trending = true)
  AND (? = false OR p.bestseller = true)
  AND (? = false OR p.created_at >= DATE_SUB(NOW(), INTERVAL 7 DAY))
  AND (? = false OR EXISTS (
    SELECT 1 FROM product_variants pv WHERE pv.product_id = p.id AND pv.discount > 0 AND pv.deleted_at IS NULL
  ))
ORDER BY
  CASE WHEN ? = 'popular' THEN p.review_count END DESC,
  CASE WHEN ? = 'popular' THEN p.rating END DESC,
  CASE WHEN ? = 'rating' THEN p.rating END DESC,
  CASE WHEN ? = 'trending' THEN p.trending END DESC,
  CASE WHEN ? = 'bestsellers' THEN p.bestseller END DESC,
  CASE WHEN ? = 'price-asc' THEN p.min_price END ASC,
  CASE WHEN ? = 'price-desc' THEN p.max_price END DESC,
  CASE WHEN ? = 'newest' THEN p.created_at END DESC,
  p.created_at DESC
LIMIT ? OFFSET ?
`

type SearchProductsParams struct {
	Q              interface{}        `json:"q"`
	Category       sql.NullString     `json:"category"`
	Subcategory    sql.NullString     `json:"subcategory"`
	Brand          sql.NullString     `json:"brand"`
	Gender         NullProductsGender `json:"gender"`
	VendorID       *types.BinaryUUID  `json:"vendor_id"`
	Size           sql.NullString     `json:"size"`
	Color          sql.NullString     `json:"color"`
	MinPrice       sql.NullString     `json:"min_price"`
	MaxPrice       sql.NullString     `json:"max_price"`
	MinRating      sql.NullString     `json:"min_rating"`
	FeaturedOnly   interface{}        `json:"featured_only"`
	TrendingOnly   interface{}        `json:"trending_only"`
	BestsellerOnly interface{}        `json:"bestseller_only"`
	NewArrivalOnly interface{}        `json:"new_arrival_only"`
	OnSaleOnly     interface{}        `json:"on_sale_only"`
	SortBy         interface{}        `json:"sort_by"`
	Limit          int32              `json:"limit"`
	Offset         int32              `json:"offset"`
}

func (q *Queries) SearchProducts(ctx context.Context, arg SearchProductsParams) ([]Product, error) {
	rows, err := q.db.QueryContext(ctx, searchProducts,
		arg.Q,
		arg.Q,
		arg.Q,
		arg.Q,
		arg.Category,
		arg.Category,
		arg.Category,
		arg.Subcategory,
		arg.Subcategory,
		arg.Brand,
		arg.Brand,
		arg.Gender,
		arg.Gender,
		arg.VendorID,
		arg.VendorID,
		arg.Size,
		arg.Size,
		arg.Color,
		arg.Color,
		arg.MinPrice,
		arg.MinPrice,
		arg.MaxPrice,
		arg.MaxPrice,
		arg.MinRating,
		arg.MinRating,
		arg.FeaturedOnly,
		arg.TrendingOnly,
		arg.BestsellerOnly,
		arg.NewArrivalOnly,
		arg.OnSaleOnly,
		arg.SortBy,
		arg.SortBy,
		arg.SortBy,
		arg.SortBy,
		arg.SortBy,
		arg.SortBy,
		arg.SortBy,
		arg.SortBy,
		arg.Limit,
		arg.Offset,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []Product{}
	for rows.Next() {
		var i Product
		if err := rows.Scan(
			&i.ID,
			&i.VendorID,
			&i.CategoryID,
			&i.Name,
			&i.Description,
			&i.Brand,
			&i.Gender,
			&i.Sku,
			&i.MinPrice,
			&i.MaxPrice,
			&i.TotalStock,
			&i.Rating,
			&i.ReviewCount,
			&i.Status,
			&i.Bestseller,
			&i.NewArrival,
			&i.Featured,
			&i.Trending,
			&i.CreatedAt,
			&i.UpdatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

